mapper.select:
SELECT sms_id, phone, sms_type, content, code,
       send_status, send_time, expire_time, create_time
FROM sms_record
WHERE phone = #{phone}

    AND sms_type = #{smsType}

ORDER BY create_time DESC

mapper.update:
UPDATE sms_record
SET send_status = #{sendStatus}
WHERE sms_id = #{smsId}
